//$Id$
import { PATH_ELEMENT } from '../../../../core/element-constants';
import { TRACK_LEGEND_CLASSNAME, TRACK_FLASH_CLASSNAME, TRACK_SYMBOL_CLASSNAME } from '../../../../legend/legend-constants';
import { CHART_BRUSH_HELPERS } from '../../../../brush/chart-helpers/brush-helpers';
import { d3_line, d3_curves } from '../../../../core/d3-constants';
import { translateString } from '../../../../utils/svg-transforms';
import { getHandleData } from '../../../../legend/size-legend/slider/size-slider-helpers';
import { getDisabledOptions } from '../../../../legend/events/legend-event-helpers';
import { pointMark } from '../../../../mark/helper/custom-mark/point-mark';
import { helper } from '../../../../legend/size-legend/slider/tracker-parser';

function StyleTrack(behaviourEventInstance, selectionManager, selection) {
    let eventManager = this,
        chart = eventManager.chart,
        point = selectionManager.point,
        _instance = behaviourEventInstance.instance,
        { options } = _instance,
        { component, extent } = options,
        { element, brushOptions } = component,
        { isHorizontal, config } = brushOptions,
        filterConfig = getDisabledOptions(config);

    if (!filterConfig.track.fillColor) {
        return;
    }

    let groupEle = element.selectAll(`g.${TRACK_LEGEND_CLASSNAME}-selection`),
        trackEle = groupEle.selectAll(`${PATH_ELEMENT}.${TRACK_FLASH_CLASSNAME}`),
        symbolEle = groupEle.selectAll(`${PATH_ELEMENT}.${TRACK_SYMBOL_CLASSNAME}`),
        data = getHandleData(brushOptions, point);

    let _symbolConfig = pointMark(helper(component._parser.selectionTrackSpec).symbolSpec).config; // TODO: component._parser

    // Symbol
    symbolEle.attrs({
        d: (d, i) => _symbolConfig.d(data[i]),
        transform: (d, i) => {
            let _position = _symbolConfig
                .transform(data[i])
                .replace('translate(', '')
                .replace(')', '')
                .split(' ')
                .map(_ => +_); // TODO
            return translateString(isHorizontal ? [selection[i], _position[1]] : [_position[0], selection[i]]);
        }
    });

    // Flash
    let desc = clip4Track(selection, extent, isHorizontal),
        clipSrc = CHART_BRUSH_HELPERS.GET_CLIP(_instance, [0, 0], chart, `size_slider_brush_selection-track`, { desc });

    trackEle.attr('clip-path', clipSrc);
}

function clip4Track(selection, extent, isHorizontal) {
    let lineClosed = d3_line().curve(d3_curves('linear-closed')),
        points = isHorizontal
            ? [
                  [selection[0], extent[0][1]],
                  [selection[1], extent[0][1]],
                  [selection[1], extent[1][1]],
                  [selection[0], extent[1][1]]
              ]
            : [
                  [extent[0][0], selection[0]],
                  [extent[1][0], selection[0]],
                  [extent[1][0], selection[1]],
                  [extent[0][0], selection[1]]
              ];

    return lineClosed(points);
}

export { StyleTrack };
